-- =============================================================================
-- seed_lms_curriculum.sql -- Canonical WS7 curriculum as the catalogue (v0.43.0)
-- Upserts all 90 WS7 module shells by code (code/domain/level/owner/cadence/
-- mandatory/category), then archives the legacy code-less demo modules (the
-- Employee Handbook is preserved). DATA, not schema. Idempotent (upsert by code).
-- Bodies are NOT touched here (authored separately, e.g. seed_fnd103_content.sql).
-- All shells ship DRAFT except FND-103 (PUBLISHED, has content).
-- =============================================================================

BEGIN;

ON CONFLICT (code) WHERE code IS NOT NULL DO UPDATE SET
  title = EXCLUDED.title, category = EXCLUDED.category, summary = EXCLUDED.summary,
  status = EXCLUDED.status, domain = EXCLUDED.domain, level = EXCLUDED.level,
  is_mandatory = EXCLUDED.is_mandatory, cadence = EXCLUDED.cadence, owner = EXCLUDED.owner,
  pass_mark = EXCLUDED.pass_mark, estimated_minutes = EXCLUDED.estimated_minutes,
  updated_at = CURRENT_TIMESTAMP;

-- archive the legacy code-less demo modules (preserve the Employee Handbook)
UPDATE "learning_modules" SET status = 'ARCHIVED', updated_at = CURRENT_TIMESTAMP
WHERE code IS NULL AND COALESCE(category,'') <> 'HANDBOOK' AND title NOT ILIKE '%handbook%';

COMMIT;